3269: fn micro_task_updated_at(micro_task: &locus::TrackedMicroTask) -> String {
3270:     if let Some(completed_at) = micro_task.completed_at {
3271:         return completed_at.to_rfc3339();
3272:     }
3273:     if let Some(started_at) = micro_task.started_at {
3274:         return started_at.to_rfc3339();
3275:     }
3276:     if let Some(iteration) = micro_task.iterations.iter().max_by_key(|iteration| {
3277:         (
3278:             iteration.completed_at,
3279:             iteration.started_at,
3280:             iteration.iteration,
3281:         )
3282:     }) {
3283:         return iteration.completed_at.to_rfc3339();
3284:     }
3285:     "1970-01-01T00:00:00Z".to_string()
3286: }
